30	/**
31	 * Create a chat room message from agent response
32	 */
33	function createChatRoomMessage(
34	  response: ProviderResponse,
35	  agentId: string
36	): ChatRoomMessage | null {
37	  const timestamp = new Date().toISOString();
38	  
39	  switch (response.type) {
40	    case "text":
41	      return {
42	        type: "text",
43	        content: response.content || "",
44	        agentId,
45	        timestamp,
46	      };
47	      
48	    case "image":
49	      return {
50	        type: "image",
51	        content: response.content || "Image captured",
52	        imageData: response.imageData,
53	        agentId,
54	        timestamp,
55	      };
56	      
57	    case "tool_use":
58	      if (response.toolName === "capture_screen") {
59	        return {
60	          type: "command",
61	          content: `Executing screen capture: ${response.toolName}`,
62	          agentId,
63	          timestamp,
64	          metadata: {
65	            command: response.toolName,
66	          },
67	        };
68	      }
69	      break;
70	      
71	    case "error":
72	      return {
73	        type: "text",
74	        content: `Error: ${response.error}`,
75	        agentId,
76	        timestamp,
77	      };
78	  }
79	  
80	  return null;
81	}
