async function* runDelegatedSubAgent(
  subAgentId: string,
  instructions: string,
  request: ChatRequest,
  abortController: AbortController,
  debugMode: boolean,
  delegationChain: string[],
  resultHolder: { text: string; errored: boolean; errorMessage?: string }
): AsyncGenerator<StreamResponse> {
  const subRequest: ChatRequest = {
    ...request,
    message: instructions,
    sessionId: undefined,
    workingDirectory: undefined,
  };

  for await (const streamResponse of executeSingleAgent(
    subAgentId,
    subRequest,
    null,
    abortController,
    debugMode,
    delegationChain
  )) {
    if (streamResponse.type === "error") {
      resultHolder.errored = true;
      resultHolder.errorMessage = streamResponse.error;
      continue;
    }

    if (streamResponse.type === "done") {
      continue;
    }

    if (streamResponse.type === "claude_json") {
      const data = streamResponse.data as any;
      if (data?.type === "chat_room_message" && data.message?.type === "text") {
        resultHolder.text += data.message.content || "";
      }
    }

    yield streamResponse;
  }
