  ProviderChatRequest,
  ProviderOptions,
  ProviderResponse,
} from "../../providers/types.ts";

function makeProvider(
  id: string,
  responder: (request: ProviderChatRequest) => ProviderResponse[]
): AgentProvider {
  return {
    id,
    name: id,
    type: "claude-code",
    supportsImages: () => false,
    async *executeChat(request: ProviderChatRequest, _options?: ProviderOptions) {
      for (const response of responder(request)) {
        yield response;
      }
    },
  };
}

async function collectStream(response: Response) {
  const reader = response.body!.getReader();
  const decoder = new TextDecoder();
  let streamData = "";

  while (true) {
    const { done, value } = await reader.read();
    if (done) break;
    streamData += decoder.decode(value);
  }

  return streamData
    .split("\n")
    .filter((line) => line.trim())
    .map((line) => JSON.parse(line));
}

function makeContext(chatRequest: ChatRequest): Partial<Context> {
  return {
    req: {
      json: async () => chatRequest,
    } as any,
    var: {
      config: { debugMode: false },
    } as any,
  };
}

